query.sparql:
SELECT ?person ?personLabel WHERE {
  wd:Q18222 wdt:P170 ?person.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?animal ?animalLabel WHERE {
  ?operation wdt:P31 wd:Q20056524;  # military operation
             wdt:P463 wd:Q328;      # part of Australian Defence Force
             wdt:P179 ?animal.
  ?animal wdt:P31 ?type.
  ?type wdt:P279* wd:Q729.          # instance of animal
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?character WHERE {
  ?character wdt:P31 wd:Q8261;
             wdt:P50 wd:Q198202;
             wdt:P50 wd:Q198203.
  FILTER NOT EXISTS { ?character wdt:P451 ?partner. }
}

SELECT ?founder ?founderLabel WHERE {
  ?founder wdt:P31 wd:Q5;  # instance of human
           wdt:P112 wd:Q214;  # founder of Tencent
           wdt:P39 wd:Q13218629.  # member of National People's Congress
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work ?workLabel WHERE {
  wd:Q10068 wdt:P800 ?work.
  ?work wdt:P31 wd:Q7725634;  # instance of a manga
        wdt:P921 wd:Q82955.   # topic of middle school students
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?exchange ?exchangeLabel WHERE {
  wd:Q1884 wdt:P414 ?exchange.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work WHERE {
  wd:Q1981 wdt:P800 ?work.
  FILTER(?work != wd:Q1981)  # Exclude the Witcher series
}

SELECT ?person1 ?person2 ?state WHERE {
  VALUES ?person1 { wd:Q104203202 }  # Brooke Raboutou
  VALUES ?person2 { wd:Q104203203 }  # Colin Duffy
  ?person1 wdt:P276 ?state.
  ?person2 wdt:P276 ?state.
}

SELECT ?boilingPoint WHERE {
  wd:Q283 wdt:P2044 ?boilingPoint.
}

SELECT ?school ?schoolLabel WHERE {
  wd:Q32940 wdt:P69 ?school.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?island WHERE {
  wd:Q252 wdt:P31 wd:Q23424;
            wdt:P2046 ?population;
            wdt:P625 ?coordinates.
  ?island wdt:P31 wd:Q23424;
          wdt:P2046 ?population.
} LIMIT 1

SELECT ?game WHERE {
  ?game wdt:P31 wd:Q7889;  # instance of video game
        wdt:P400 wd:Q1860. # available on PlayStation 4
  FILTER(CONTAINS(LCASE(STR(?game)), "don't starve"))
}

SELECT (COUNT(?secretary) AS ?count) WHERE {
  ?secretary wdt:P31 wd:Q1860;  # instance of political office
              wdt:P39 wd:Q1860;  # position held
              wdt:P580 ?startTime. # start time of the office
  FILTER(?startTime < "1964-01-01T00:00:00Z"^^xsd:dateTime) # before Brezhnev's term
}

SELECT (COUNT(DISTINCT ?president) AS ?numberOfPresidents) WHERE {
  ?president wdt:P31 wd:Q5;
              wdt:P39 wd:Q30431;
              wdt:P580 ?startDate.
  FILTER(?startDate >= "1990-01-01T00:00:00Z"^^xsd:dateTime)
}

SELECT ?medal WHERE {
  wd:Q2020 wdt:P1344 wd:Q2020;
            wdt:P166 ?medal.
  ?medal wdt:P31 wd:Q146;
         wdt:P1346 wd:Q1000000.
  wd:Q1000000 wdt:P1344 wd:Q2020;
              wdt:P166 wd:Q123456.
}

SELECT (COUNT(?season) AS ?championships) WHERE {
  ?team wdt:P31 wd:Q36655;
        wdt:P1346 ?season.
  ?season wdt:P585 ?date.
  FILTER(?date >= "1990-01-01T00:00:00Z"^^xsd:dateTime && ?date < "2000-01-01T00:00:00Z"^^xsd:dateTime)
} GROUP BY ?team HAVING(COUNT(?season) >= 2)

SELECT ?award WHERE {
  wd:Q17340 wdt:P166 ?award.
  FILTER(?award = wd:Q37922)
}

SELECT ?item WHERE {
  ?item wdt:P31 wd:Q515;  # instance of a city
        wdt:P17 wd:Q40;   # located in Italy
        wdt:P576 ?date.   # point in time when it was part of the Austrian Empire
  FILTER(?date >= "1815-01-01T00:00:00Z"^^xsd:dateTime && ?date <= "1866-01-01T00:00:00Z"^^xsd:dateTime)
}

SELECT ?founder1 ?founder2 ?university WHERE {
  ?founder1 wdt:P31 wd:Q42963; wdt:P112 wd:Q100000; wdt:P69 ?university.
  ?founder2 wdt:P31 wd:Q42963; wdt:P112 wd:Q100000; wdt:P69 ?university.
  FILTER(?founder1 != ?founder2)
} GROUP BY ?founder1 ?founder2 ?university HAVING(COUNT(?founder1) >= 2)

SELECT ?partner ?partnerLabel ?language ?languageLabel WHERE {
  wd:Q22688 wdt:P1559 ?partner.
  ?partner wdt:P1412 ?language.
  FILTER(?language = wd:Q1860)
}

SELECT (AVG(?spouseCount) AS ?averageSpouses) WHERE {
  ?headOfState wdt:P39 wd:Q13218629;  # instance of head of state
               wdt:P26 ?spouse.       # spouse property
  {
    SELECT ?headOfState (COUNT(?spouse) AS ?spouseCount) WHERE {
      ?headOfState wdt:P39 wd:Q13218629;  # instance of head of state
                   wdt:P26 ?spouse.       # spouse property
    }
    GROUP BY ?headOfState
  }
}

SELECT (COUNT(?event) AS ?eventCount) WHERE {
  ?event wdt:P31 wd:Q202202;  # instance of Formula 1 event
         wdt:P625 ?location.   # has coordinates
  ?location wdt:P31 wd:Q23431. # located on AVUS
}

SELECT ?verb ?lemma WHERE {
  ?verb wdt:P31 wd:Q1860;  # instance of verb
        wdt:P2052 ?lemma.  # has lemma
  FILTER(CONTAINS(STR(?lemma), "uş"))
}

SELECT ?country WHERE {
  wd:Q144 wdt:P27 ?country.
}

SELECT ?country (COUNT(?winner) AS ?winnerCount) WHERE {
  ?winner wdt:P166 wd:Q192202.
  ?winner wdt:P27 ?country.
} GROUP BY ?country ORDER BY DESC(?winnerCount) LIMIT 1 OFFSET 1

SELECT ?musicStyle WHERE {
  wd:Q1860 wdt:P136 ?musicStyle.
  FILTER(?musicStyle = wd:Q7348)  # Q7348 is the identifier for rock music
}

SELECT ?item WHERE {
  ?item wdt:P281 "32423" .
  ?item wdt:P131 ?place .
  ?place rdfs:label "Minden"@en .
}

SELECT ?event ?date WHERE {
  wd:Q195202 wdt:P1344 ?event.
  ?event wdt:P580 ?date.
  ?event wdt:P31 wd:Q207202.
}

SELECT ?year ?lifeExpectancy WHERE {
  wd:Q7940 wdt:P2250 ?lifeExpectancy.
  ?year wdt:P585 ?date.
  FILTER(YEAR(?date) > 1999)
}

SELECT ?year ?population WHERE {
  wd:Q1022 wdt:P1082 ?population.
  ?population wdt:P585 ?year.
  FILTER(?year > "2006-01-01T00:00:00Z"^^xsd:dateTime)
}

SELECT ?event WHERE {
  wd:Q1860 wdt:P31 wd:Q1656682;
            wdt:P585 ?date.
  ?event wdt:P31 wd:Q1656682;
         wdt:P585 ?date.
  ?event wdt:P164 wd:Q1860.
}

SELECT (COUNT(?brother) AS ?livingBrothers) WHERE {
  wd:Q180200 wdt:P3373 ?brother.
  ?brother wdt:P570 ?deathDate.
  FILTER(?deathDate > "2023-10-01T00:00:00Z"^^xsd:dateTime)
}

SELECT ?deathManner WHERE {
  wd:Q22687 wdt:P570 ?deathDate.
  wd:Q22687 wdt:P1196 ?deathManner.
}

SELECT ?industry WHERE {
  wd:Q173202 wdt:P452 ?industry.
}

SELECT ?name WHERE {
  wd:Q30 rdfs:label ?name .
  FILTER(LANG(?name) = "tr")
}

SELECT ?height WHERE {
  wd:Q1008 wdt:P2048 ?height.
}

SELECT ?harzLabel WHERE {
  wd:Q2002028 rdfs:label ?harzLabel .
  FILTER(LANG(?harzLabel) = "zh")
}

SELECT (COUNT(?airport) AS ?numberOfAirports) WHERE {
  ?airport wdt:P31 wd:Q1248784;  # instance of international airport
           wdt:P131 wd:Q2028.    # located in Hamburg
}

SELECT (COUNT(DISTINCT ?album) AS ?albumCount) WHERE {
  ?album wdt:P31 wd:Q482994;
         wdt:P175 wd:Q42.
}

SELECT (COUNT(DISTINCT ?album) AS ?albumCount) WHERE {
  ?album wdt:P31 wd:Q482994;
         wdt:P175 wd:Q5520.
}

SELECT (COUNT(?album) AS ?albumCount) WHERE {
  wd:Q2202028 wdt:P136 wd:Q192291;
               wdt:P31 wd:Q482994;
               wdt:P50 ?artist.
  BIND(wd:Q2202028 AS ?artist)
  ?album wdt:P175 ?artist.
}

SELECT (COUNT(DISTINCT ?civilization) AS ?count) WHERE {
  ?civilization wdt:P31 wd:Q43229.
}

SELECT (COUNT(DISTINCT ?year) AS ?numberOfYears) WHERE {
  ?player wdt:P106 wd:Q36656;  # NBA player
          wdt:P1346 wd:Q197;    # NBA All-Defensive Team
          wdt:P580 ?startDate.   # start date of the award
  BIND(YEAR(?startDate) AS ?year)
}

SELECT (COUNT(DISTINCT ?year) AS ?count) WHERE {
  {
    SELECT ?year WHERE {
      wd:Q11541 wdt:P802 ?teamAward.
      wd:Q11541 wdt:P585 ?date.
      BIND(YEAR(?date) AS ?year)
    }
  }
  UNION
  {
    SELECT ?year WHERE {
      wd:Q237 wdt:P802 ?teamAward.
      wd:Q237 wdt:P585 ?date.
      BIND(YEAR(?date) AS ?year)
    }
  }
  FILTER(?year IN (SELECT ?year WHERE {
    wd:Q11541 wdt:P802 ?teamAward.
    wd:Q237 wdt:P802 ?teamAward.
    wd:Q11541 wdt:P585 ?date.
    wd:Q237 wdt:P585 ?date.
    BIND(YEAR(?date) AS ?year)
  }))
}

SELECT (COUNT(?work) AS ?workCount) WHERE {
  ?work wdt:P31 wd:Q7725634;  # instance of literary work
        wdt:P50 wd:Q19893.    # authored by Richard Bachman
}

SELECT (COUNT(?work) AS ?notableWorksCount) WHERE {
  ?author wdt:P31 wd:Q5;
          wdt:P106 wd:Q8261;
          rdfs:label "Sarah J. Maas"@en.
  ?work wdt:P50 ?author.
}

SELECT ?university WHERE {
  wd:Q196052 wdt:P69 ?university.
  ?university wdt:P31 wd:Q3918.
  ?university wdt:P463 wd:Q196052.
} LIMIT 1

SELECT (COUNT(?child) AS ?numberOfChildren) WHERE {
  wd:Q9370 wdt:P25 ?child.
  ?child wdt:P31 wd:Q206577.
}

SELECT (COUNT(?child) AS ?numberOfChildren) WHERE {
  wd:Q1290 wdt:P26 wd:Q202202;
  wd:Q202202 wdt:P40 ?child.
}

SELECT (COUNT(DISTINCT ?animal) AS ?totalZodiacAnimals) WHERE {
  ?animal wdt:P31 wd:Q24680.
}

SELECT (COUNT(?city) AS ?cityCount) WHERE {
  ?city wdt:P31 wd:Q515;  # instance of city
        wdt:P131 wd:Q134204;  # located in the Pearl River Delta
}

SELECT (COUNT(DISTINCT ?cityState) AS ?count) WHERE {
  ?cityState wdt:P31 wd:Q515;  # instance of city
              wdt:P31 wd:Q839954. # instance of city-state
}

SELECT (COUNT(DISTINCT ?business) AS ?businessCount) WHERE {
  ?business wdt:P31 wd:Q4830453;  # instance of business
            wdt:P112 wd:Q42.      # founded by Steve Jobs
}

SELECT (COUNT(?country) AS ?countryCount) WHERE {
  ?country wdt:P31 wd:Q3624078;  # instance of country
           wdt:P1083 ?democracyIndex;  # democracy index
           wdt:P5008 wd:Q100;  # drives on the left
           FILTER(?democracyIndex > 7)
}

SELECT (COUNT(?country) AS ?numberOfCountries) WHERE {
  ?country wdt:P31 wd:Q36255.
  FILTER NOT EXISTS { ?country wdt:P463 wd:Q206613. }
}

SELECT (COUNT(DISTINCT ?country) AS ?countryCount) WHERE {
  ?country wdt:P31 wd:Q36255;  # instance of country
           wdt:P30 wd:Q continent;  # part of continent
           wdt:P2046 wd:Q21.  # located in South America
}

SELECT (COUNT(?dragon) AS ?dragonCount) WHERE {
  ?dragon wdt:P31 wd:Q206202;  # instance of fictional dragon
          wdt:P361 wd:Q233;    # part of Game of Thrones
}

SELECT (COUNT(?award) AS ?emmy_count) WHERE {
  wd:Q202202 wdt:P166 ?award.
  ?award wdt:P31 wd:Q5397.
}

SELECT (COUNT(?film) AS ?filmCount) WHERE {
  ?film wdt:P31 wd:Q11424;  # instance of film
        wdt:P144 wd:Q104202;  # based on the original Ghost in the Shell Manga
}

SELECT (COUNT(?king) AS ?count) WHERE {
  ?king wdt:P31 wd:Q1052020;  # instance of king
        wdt:P27 wd:Q142;      # citizen of France
        wdt:P1192 ?cause.     # cause of death
  FILTER(?cause != wd:Q1184126) # not died of natural causes
}

SELECT (COUNT(?givenName) AS ?numberOfGivenNames) WHERE {
  wd:Q21678 wdt:P735 ?givenName.
}

SELECT (COUNT(DISTINCT ?mayor) AS ?femaleMayorCount) WHERE {
  ?mayor wdt:P31 wd:Q5;  # instance of human
         wdt:P39 wd:Q134162;  # position held: mayor
         wdt:P21 wd:Q6581072.  # gender: female
}

SELECT (COUNT(DISTINCT ?headOfState) AS ?numberOfHeadsOfState) WHERE {
  ?headOfState wdt:P39 wd:Q217.
}

SELECT (COUNT(?article) AS ?articleCount) WHERE {
  ?article wdt:P31 wd:Q13442814;  # instance of scholarly article
           wdt:P921 wd:Q151186;   # subject of ImageNet
}

SELECT ?inhabitants WHERE {
  wd:Q2270 wdt:P1082 ?inhabitants.
}

SELECT (COUNT(DISTINCT ?writer) AS ?count) WHERE {
  ?writer wdt:P31 wd:Q8261;  # instance of human
          wdt:P166 wd:Q37922. # awarded Nobel Prize
  ?writer wdt:P27 wd:Q17.    # nationality Japan
}

SELECT (COUNT(DISTINCT ?language) AS ?languageCount) WHERE {
  ?language wdt:P31 wd:Q34770;  # instance of language
            wdt:P463 wd:Q668;   # part of the Indian linguistic family
}

SELECT (COUNT(DISTINCT ?color) AS ?numberOfColors) WHERE {
  ?water wdt:P31 wd:Q283.
  ?water wdt:P462 ?color.
}

SELECT (COUNT(DISTINCT ?location) AS ?numberOfLocations) WHERE {
  wd:Q5582 wdt:P937 ?location.
}

SELECT (COUNT(?month) AS ?numberOfMonths) WHERE {
  ?month wdt:P31 wd:Q25279;  # instance of month
         wdt:P625 ?coordinate.  # has coordinates
  FILTER(?coordinate = "10.4515, 51.1657")  # coordinates for Germany
}

SELECT (COUNT(?movie) AS ?movieCount) WHERE {
  ?movie wdt:P31 wd:Q11424;  # instance of film
         wdt:P57 wd:Q32904;  # directed by James Cameron
         wdt:P publication_date ?date.
  FILTER(?date < "2010-01-01T00:00:00Z"^^xsd:dateTime)
}

SELECT (COUNT(?movie) AS ?movieCount) WHERE {
  ?movie wdt:P31 wd:Q11424;
         wdt:P57 wd:Q32973.
}

SELECT (COUNT(DISTINCT ?scale) AS ?numberOfScales) WHERE {
  ?scale wdt:P31 wd:Q1910.
}

SELECT (COUNT(?holiday) AS ?numberOfHolidays) WHERE {
  ?holiday wdt:P31 wd:Q11641;  # instance of public holiday
           wdt:P276 wd:Q183;   # located in Bavaria
}

SELECT (COUNT(?work) AS ?numberOfWorks) WHERE {
  ?author wdt:P31 wd:Q5;
          wdt:P106 wd:Q8261;
          rdfs:label "Oscar Wilde"@en.
  ?work wdt:P50 ?author.
  FILTER(?work != wd:Q12345)  # Replace wd:Q12345 with the actual QID for The Picture of Dorian Gray
}

SELECT (COUNT(?work) AS ?workCount) WHERE {
  ?work wdt:P31 wd:Q7725634;
        wdt:P50 wd:Q2008.
}

SELECT (COUNT(?occupation) AS ?occupationCount) WHERE {
  wd:Q209 wdt:P106 ?occupation.
}

SELECT (COUNT(DISTINCT ?performer) AS ?count) WHERE {
  ?performer wdt:P31 wd:Q33999;  # instance of performer
             wdt:P27 wd:Q1860.  # citizen of United Kingdom
  ?performer wdt:P106 wd:Q32996.  # occupation is Spider-Man performer
}

SELECT (COUNT(?language) AS ?numberOfLanguages) WHERE {
  wd:Q30 wdt:P37 ?language.
}

SELECT (COUNT(?language) AS ?numberOfLanguages) WHERE {
  wd:Q8436 wdt:P37 ?language.
}

SELECT (SUM(?oscarWins) AS ?totalOscars) WHERE {
  ?movie wdt:P57 wd:Q32968;  # directed by Hayao Miyazaki
         wdt:P166 ?award.    # has received an award
  ?award wdt:P31 wd:Q19020;  # is an award
         wdt:P166 wd:Q32934.  # is an Oscar
  OPTIONAL { ?award wdt:P1545 ?oscarWins. }
}

SELECT (COUNT(DISTINCT ?painting) AS ?numberOfPaintings) WHERE {
  ?painting wdt:P31 wd:Q3305213;  # instance of painting
            wdt:P170 wd:Q5582;    # created by Pablo Picasso
            wdt:P276 ?museum.     # located in a museum
}

SELECT (MAX(?numberOfPlayers) AS ?maxPlayers) WHERE {
  ?game wdt:P31 wd:Q1922;  # instance of board game
        wdt:P2002 ?numberOfPlayers.  # number of players
  FILTER(?game = wd:Q1922)  # filter for "Mensch ärgere dich nicht"
}

SELECT (COUNT(?victim) AS ?numberOfVictims) WHERE {
  wd:Q1341000 wdt:P1603 ?victim.
}

SELECT ?deathCount WHERE {
  wd:Q1968 wdt:P1120 ?deathCount.
}

SELECT (COUNT(DISTINCT ?person) AS ?numberOfWinners) WHERE {
  ?person wdt:P166 wd:Q37922.
}

SELECT (COUNT(?pitchClass) AS ?numberOfPitchClasses) WHERE {
  ?chromaticScale wdt:P31 wd:Q215032;  # instance of chromatic scale
                  wdt:P527 ?pitchClass.  # has part
}

SELECT (COUNT(?play) AS ?numberOfPlays) WHERE {
  ?play wdt:P31 wd:Q3305213;  # instance of play
        wdt:P577 ?publicationDate.  # publication date
  FILTER(YEAR(?publicationDate) >= 1500 && YEAR(?publicationDate) < 1600)  # 16th century
  ?play wdt:P50 wd:Q692.  # authored by William Shakespeare
}

SELECT (COUNT(?poem) AS ?numberOfPoems) WHERE {
  ?poem wdt:P31 wd:Q22699;
        wdt:P50 wd:Q180;
}

SELECT (COUNT(DISTINCT ?party) AS ?numberOfParties) WHERE {
  ?party wdt:P31 wd:Q7275;  # instance of political party
         wdt:P463 wd:Q183;  # member of the German Bundestag
}

SELECT (COUNT(DISTINCT ?position) AS ?numberOfPositions) WHERE {
  wd:Q2534 wdt:P413 ?position.
}

SELECT (COUNT(?prize) AS ?numberOfPrizes) WHERE {
  ?prize wdt:P31 wd:Q37922;
         wdt:P1921 wd:Q37922.
}

SELECT ?mission ?missionLabel WHERE {
  ?mission wdt:P31 wd:Q22600584;  # instance of space mission
           wdt:P1923 wd:Q865;      # operated by SpaceX
           wdt:P580 ?launchDate.   # launch date
  OPTIONAL { ?mission wdt:P580 ?failedLaunchDate. }
  FILTER(?failedLaunchDate < ?launchDate)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT (COUNT(DISTINCT ?nominator) AS ?count) WHERE {
  ?nominator wdt:P31 wd:Q5;  # instance of human
             wdt:P166 wd:Q37922. # nominated for Nobel Prize in Chemistry
  FILTER NOT EXISTS { ?nominator wdt:P166 wd:Q37922. } # not a winner
}

SELECT (COUNT(?season) AS ?numberOfSeasons) WHERE {
  wd:Q2022020 wdt:P2048 ?season.
}

SELECT (COUNT(?seat) AS ?numberOfSeats) WHERE {
  ?bundestag wdt:P31 wd:Q13218629;
             wdt:P2046 ?seat.
}

SELECT (COUNT(?sibling) AS ?numberOfSiblings) WHERE {
  ?author wdt:P31 wd:Q32904;  # instance of author
          wdt:P106 wd:Q8261;  # occupation is writer
          rdfs:label "Louisa May Alcott"@en.
  ?author wdt:P3373 ?sibling.  # has sibling
}

SELECT (COUNT(DISTINCT ?resort) AS ?numberOfResorts) WHERE {
  ?resort wdt:P31 wd:Q22698;
           wdt:P17 wd:Q142.
}

SELECT (COUNT(?song) AS ?songCount) WHERE {
  ?song wdt:P31 wd:Q639577;  # instance of song
        wdt:P170 wd:Q200001; # composed by Jay Chou
        wdt:P361 ?album.     # part of an album
  FILTER NOT EXISTS { ?album wdt:P175 wd:Q200001 } # not released in his own albums
}

SELECT (COUNT(?work) AS ?count) WHERE {
  ?work wdt:P144 ?venom .
  ?venom wdt:P31 wd:Q100 .
  ?venom wdt:P180 wd:Q620 .
}

SELECT (COUNT(?spouse) AS ?numberOfSpouses) WHERE {
  wd:Q186202 wdt:P26 ?spouse.
}

SELECT ?place WHERE {
  ?place wdt:P31 wd:Q515;  # instance of a populated place
         wdt:P625 ?coordinates.
  FILTER(geof:distance(?coordinates, "Point(8.57 47.8)"^^geo:wktLiteral) > 0)
  FILTER(geof:lat(?coordinates) > 47.8)
}

SELECT (COUNT(?award) AS ?count) WHERE {
  wd:Q1981 wdt:P166 ?award.
  ?award wdt:P31 wd:Q19020.
}

SELECT (COUNT(?olympicGames) AS ?count) WHERE {
  wd:Q25343 wdt:P1344 ?olympicGames.
}

SELECT (COUNT(?election) AS ?electionCount) WHERE {
  ?person wdt:P31 wd:Q5;
          wdt:P39 wd:Q1860;
          rdfs:label "Oskar Lafontaine"@de.
  ?election wdt:P39 ?person.
}

SELECT (COUNT(DISTINCT ?war) AS ?warCount) WHERE {
  ?war wdt:P31 wd:Q1656682;  # instance of war
       wdt:P463 wd:Q17.      # participant is the Empire of Japan
}

SELECT (COUNT(?member) AS ?count) WHERE {
  ?member wdt:P31 wd:Q5;  # instance of human
          wdt:P800 wd:Q123456;  # part of the founding members of "The Bridge"
          wdt:P21 wd:Q6581072.  # gender female
}

SELECT ?animal ?lifespan WHERE {
  {
    SELECT ?animal (MAX(?lifespan) AS ?lifespan) WHERE {
      VALUES ?animal { wd:Q224 wd:Q144 }
      ?animal wdt:P225 ?name.
      ?animal wdt:P2047 ?lifespan.
    }
    GROUP BY ?animal
  }
} ORDER BY DESC(?lifespan) LIMIT 1

SELECT ?item ?itemLabel WHERE {
  ?item wdt:P31 wd:Q16521;  # instance of protein
        rdfs:label "TNFAIP1"@en.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT (COUNT(?award) AS ?count) WHERE {
  ?person wdt:P31 wd:Q5;
          wdt:P106 wd:Q36180;
          rdfs:label "Naomi Novik"@en.
  ?award wdt:P31 wd:Q32986;
         wdt:P winner ?person.
}

SELECT ?event ?eventLabel ?date WHERE {
  ?event wdt:P31 wd:Q1656682;  # instance of military conflict
         wdt:P17 wd:Q17;       # located in Japan
         wdt:P580 ?date.       # start time
  FILTER(CONTAINS(LCASE(STR(?eventLabel)), "mongol"))
} ORDER BY ?date

SELECT (COUNT(?award) AS ?nominationCount) WHERE {
  ?author wdt:P31 wd:Q32955;
          wdt:P106 wd:Q32955;
