  ?band wdt:P31 wd:Q215380.
  ?band rdfs:label "Metallica"@en.
  ?founder wdt:P161 ?band.
  ?founder wdt:P19 ?place.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
